node Tag { has text: str; }

walker JoinTags {
    has parts: list = [];
    can read with Tag entry { self.parts.append(here.text); visit [-->]; }
}

def join_chain_labels(spec: dict) -> str {
    labels: list = list(spec["labels"]);
    if not labels { return ""; }
    head = Tag(text=str(labels[0]));
    prev = head;
    for lb in labels[1:] {
        nxt = Tag(text=str(lb));
        prev ++> nxt;
        prev = nxt;
    }
    w = head spawn JoinTags();
    return "-".join(w.parts);
}

with entry { print(join_chain_labels({"labels": ["red", "green", "blue"]})); }

walker AltSum {
    has balance: int = 0;
    has flip: int = 1;
    can tick with Beat entry {
        self.balance += self.flip * here.amt;
        self.flip = -self.flip;
        visit [-->];
    }
}

node Beat { has amt: int; }

def alternating_chain_sum(spec: dict) -> int {
    beats: list = [Beat(amt=int(n)) for n in spec["nums"]];
    if len(beats) == 0 { return 0; }
    j: int = len(beats) - 1;
    while j > 0 {
        beats[j - 1] ++> beats[j];
        j -= 1;
    }
    return (beats[0] spawn AltSum()).balance;
}

with entry { print(alternating_chain_sum({"nums": [10, 3, 2]})); }

node Slot { has q: int; }

walker Doubler {
    has picked: list = [];
    can scoop with Slot entry {
        self.picked.append(here.q * 2);
        visit [-->];
    }
}

def doubled_chain_values(spec: dict) -> list {
    slots: list = [Slot(q=int(n)) for n in spec["nums"]];
    if not slots { return []; }
    for (a, b) in zip(slots[:-1], slots[1:]) { a ++> b; }
    runner = slots[0] spawn Doubler();
    return runner.picked;
}

with entry { print(doubled_chain_values({"nums": [3, 1, 4]})); }

node Card { has word: str; }

walker LenCount {
    has chars: int = 0;
    can weigh with Card entry { self.chars += len(here.word); visit [-->]; }
}

def total_label_length(spec: dict) -> int {
    if len(spec["words"]) == 0 { return 0; }
    cards: list = [];
    for wd in spec["words"] {
        c = Card(word=str(wd));
        if cards { cards[-1] ++> c; }
        cards.append(c);
    }
    counter = cards[0] spawn LenCount();
    return counter.chars;
}

with entry { print(total_label_length({"words": ["hi", "there"]})); }

