node Gauge { has v: int; }

walker PeakTrail {
    has trail: list = [];
    has best: int = 0;
    has started: bool = False;
    can note with Gauge entry {
        if not self.started { self.best = here.v; self.started = True; }
        elif here.v > self.best { self.best = here.v; }
        self.trail.append(self.best);
        visit [-->];
    }
}

def running_max_prefix(spec: dict) -> list {
    nums: list = list(spec["nums"]);
    if not nums { return []; }
    gauges: list = [];
    for n in nums { gauges.append(Gauge(v=int(n))); }
    for i in range(1, len(gauges)) { gauges[i - 1] ++> gauges[i]; }
    hiker = gauges[0] spawn PeakTrail();
    return hiker.trail;
}

with entry { print(running_max_prefix({"nums": [3, 1, 4, 1, 5]})); }

node Sensor { has reading: int; has polled: bool = False; }

walker AvgReader {
    has readings: list = [];
    can poll with Sensor entry {
        if here.polled { return; }
        here.polled = True;
        self.readings.append(here.reading);
        visit [-->];
    }
}

def mean_reachable_val(spec: dict) -> float {
    vals: dict = dict(spec["vals"]);
    adj: dict = dict(spec["adj"]);
    grid: dict = {};
    for sid in vals.keys() { grid[sid] = Sensor(reading=int(vals[sid])); }
    for a in adj.keys() {
        for b in adj[a] { grid[a] ++> grid[b]; }
    }
    reader = grid[str(spec["start"])] spawn AvgReader();
    return round(sum(reader.readings) / len(reader.readings), 2);
}

with entry { print(mean_reachable_val({"adj": {"a": ["b", "c"], "b": [], "c": []}, "vals": {"a": 3, "b": 4, "c": 6}, "start": "a"})); }

node Town { has gain: int; }
edge Road { has toll: int; }

walker TripLedger {
    has bal: int = 0;
    can settle with Town entry {
        self.bal += here.gain;
        for e in [edge here -->] { self.bal -= e.toll; }
        visit [-->];
    }
}

def toll_trip_balance(spec: dict) -> int {
    towns: list = [Town(gain=int(g)) for g in spec["gains"]];
    tolls: list = list(spec["tolls"]);
    for i in range(len(tolls)) {
        towns[i] +>:Road(toll=int(tolls[i])):+> towns[i + 1];
    }
    ledger = towns[0] spawn TripLedger();
    return ledger.bal;
}

with entry { print(toll_trip_balance({"gains": [5, 3, 8], "tolls": [2, 4]})); }

node Page { has word: str; has taken: bool = False; }

walker InitialScan {
    has firsts: list = [];
    can skim with Page entry {
        if not here.taken {
            here.taken = True;
            self.firsts.append(here.word[0]);
            visit [-->];
        }
    }
}

def label_initial_histogram(spec: dict) -> list {
    labels: dict = dict(spec["labels"]);
    book: dict = {};
    for nid in labels.keys() { book[nid] = Page(word=str(labels[nid])); }
    for (src, outs) in spec["adj"].items() {
        for dst in outs { book[src] ++> book[dst]; }
    }
    scanner = book[str(spec["start"])] spawn InitialScan();
    counts: dict = {};
    for ch in scanner.firsts {
        if ch in counts { counts[ch] += 1; }
        else { counts[ch] = 1; }
    }
    out: list = [];
    for k in sorted(counts.keys()) { out.append([k, counts[k]]); }
    return out;
}

with entry { print(label_initial_histogram({"adj": {"n1": ["n2", "n3"], "n2": [], "n3": ["n4"], "n4": []}, "labels": {"n1": "apple", "n2": "ant", "n3": "berry", "n4": "avocado"}, "start": "n1"})); }

node Kiosk { has label: str; has cost: int; }

walker BudgetWalk {
    has budget: int = 0;
    has spent: int = 0;
    has names: list = [];
    can shop with Kiosk entry {
        if self.spent + here.cost > self.budget { disengage; }
        self.spent += here.cost;
        self.names.append(here.label);
        visit [-->];
    }
}

def budget_walk_labels(spec: dict) -> list {
    stops: list = list(spec["stops"]);
    if len(stops) == 0 { return []; }
    kiosks: list = [];
    for pr in stops { kiosks.append(Kiosk(label=str(pr[0]), cost=int(pr[1]))); }
    for i in range(len(kiosks) - 1) { kiosks[i] ++> kiosks[i + 1]; }
    shopper = kiosks[0] spawn BudgetWalk(budget=int(spec["budget"]));
    return shopper.names;
}

with entry { print(budget_walk_labels({"stops": [["a", 3], ["b", 4], ["c", 9], ["d", 1]], "budget": 8})); }
